(
    defaultPrim = "Project"
)

def Xform "Project" (
    assetInfo = {
        string identifier = "assets/hero/v003/hero.usd"
        string name = "hero_asset"
    }
    customData = {
        dictionary pipeline = {
            string department = "lighting"
            string version = "2.1"
        }
    }
)
{
    def Xform "Hero"
    {
        custom int2 custom:frameRange = (1001, 1100)
        custom string custom:shotName = "SH010"
        custom token kind = "component"
        uniform token purpose = "render"

        def Xform "Proxy"
        {
            uniform token purpose = "proxy"
        }

        def Xform "Guide"
        {
            uniform token purpose = "guide"
        }
    }
}
